//		Exec(ctx)
func (cecb *ColumnEdgeCreateBulk) OnConflictColumns(columns ...string) *ColumnEdgeUpsertBulk {
	cecb.conflict = append(cecb.conflict, sql.ConflictColumns(columns...))
	return &ColumnEdgeUpsertBulk{
		create: cecb,
	}
}

// ColumnEdgeUpsertBulk is the builder for "upsert"-ing
// a bulk of ColumnEdge nodes.
type ColumnEdgeUpsertBulk struct {
	create *ColumnEdgeCreateBulk
}

// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.ColumnEdge.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//			sql.ResolveWith(func(u *sql.UpdateSet) {
//				u.SetIgnore(columnedge.FieldID)
//			}),
//		).
//		Exec(ctx)
func (u *ColumnEdgeUpsertBulk) UpdateNewValues() *ColumnEdgeUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.ID(); exists {
				s.SetIgnore(columnedge.FieldID)
			}
			if _, exists := b.mutation.FromAsset(); exists {
				s.SetIgnore(columnedge.FieldFromAsset)
			}
			if _, exists := b.mutation.FromColumn(); exists {
				s.SetIgnore(columnedge.FieldFromColumn)
			}
			if _, exists := b.mutation.ToAsset(); exists {
				s.SetIgnore(columnedge.FieldToAsset)
			}
			if _, exists := b.mutation.ToColumn(); exists {
				s.SetIgnore(columnedge.FieldToColumn)
			}
			if _, exists := b.mutation.CodeHashFirst(); exists {
				s.SetIgnore(columnedge.FieldCodeHashFirst)
			}
			if _, exists := b.mutation.FirstSeenRunID(); exists {
				s.SetIgnore(columnedge.FieldFirstSeenRunID)
			}
			if _, exists := b.mutation.FirstSeenAt(); exists {
				s.SetIgnore(columnedge.FieldFirstSeenAt)
			}
		}
	}))
	return u
}

// Ignore sets each column to itself in case of conflict.
// Using this option is equivalent to using:
//
//	client.ColumnEdge.Create().
//		OnConflict(sql.ResolveWithIgnore()).
//		Exec(ctx)
func (u *ColumnEdgeUpsertBulk) Ignore() *ColumnEdgeUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithIgnore())
	return u
}

// DoNothing configures the conflict_action to `DO NOTHING`.
// Supported only by SQLite and PostgreSQL.
func (u *ColumnEdgeUpsertBulk) DoNothing() *ColumnEdgeUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.DoNothing())
	return u
}

// Update allows overriding fields `UPDATE` values. See the ColumnEdgeCreateBulk.OnConflict
// documentation for more info.
func (u *ColumnEdgeUpsertBulk) Update(set func(*ColumnEdgeUpsert)) *ColumnEdgeUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&ColumnEdgeUpsert{UpdateSet: update})
	}))
	return u
}

